// Portal Extensions Initialization
// This file is auto-generated by the C# deployment plugin from manifest.json

// Inject inbox extension container into navbar
function injectInboxContainer() {
    // Find the navbar weblinks ul
    const navbarWeblinks = document.querySelector('ul.nav.navbar-nav.weblinks');
    
    if (navbarWeblinks) {
        // Create the new li element with utility-nav class
        const utilityNavItem = document.createElement('li');
        utilityNavItem.className = 'utility-nav';
        
        // Create the container div
        const containerDiv = document.createElement('div');
        containerDiv.id = 'portal-inbox-extension';
        containerDiv.style.marginRight = '10px';
        
        // Append the div to the li
        utilityNavItem.appendChild(containerDiv);
        
        // Insert before the last divider (before user dropdown)
        // Find the last divider-vertical before user dropdown
        const dividers = navbarWeblinks.querySelectorAll('li.nav-item.divider-vertical');
        const lastDivider = dividers[dividers.length - 1];
        
        if (lastDivider) {
            // Insert after the last divider
            lastDivider.parentNode.insertBefore(utilityNavItem, lastDivider.nextSibling);
        } else {
            // Fallback: append to the end if no divider found
            navbarWeblinks.appendChild(utilityNavItem);
        }
        
        console.log('Inbox extension container injected into navbar');
    } else {
        console.warn('Navbar weblinks not found, could not inject inbox container');
    }
}

// Wait for all extensions to load
